SELECT ?stmt ?part ?lbl ?v ?u WHERE {
  <https://www.purl.org/futuram/example#elvGeneralComponents__V0201020102_2025> futuram:hasCompositionStatement ?stmt .
  ?stmt futuram:hasPartRelation ?pr .
  ?pr futuram:refersTo ?part ;
       futuram:hasQuantity/futuram:hasBestValue [ qudt:numericValue ?v ; qudt:unit ?u ] .
  OPTIONAL { ?part rdfs:label ?lbl }
}

