arguments.sparql_query:
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX qudt: <http://qudt.org/schema/qudt/>
SELECT ?inst ?label ?year ?mass ?massUnit WHERE {
  ?inst a ?cls .
  ?cls rdfs:subClassOf* futuram:elvDiesel .
  ?inst rdfs:label ?label .
  OPTIONAL { ?inst futuram:referenceYear ?year }
  OPTIONAL { ?inst futuram:itemMass [ qudt:numericValue ?mass ; qudt:unit ?massUnit ] }
}
ORDER BY ?label

