PREFIX qudt: <http://qudt.org/schema/qudt/>
SELECT ?alAlloy ?part ?v ?u WHERE {
  VALUES ?alAlloy {
    <https://www.purl.org/futuram/example#elvGeneralComponents_castAlAlloys__V0201020102>
    <https://www.purl.org/futuram/example#elvGeneralComponents_5xxxAlAlloy__V0201020102>
    <https://www.purl.org/futuram/example#elvGeneralComponents_6xxxAlAlloy__V0201020102>
    <https://www.purl.org/futuram/example#elvGeneralComponents_2xxxAlAlloy__V0201020102>
  }
  ?alAlloy futuram:hasCompositionStatement ?st .
  ?st futuram:hasPartRelation ?pr .
  ?pr futuram:refersTo ?part ;
      futuram:hasQuantity/futuram:hasBestValue [ qudt:numericValue ?v ; qudt:unit ?u ] .
} ORDER BY ?alAlloy DESC(?v)

