SELECT DISTINCT ?inst ?label ?year ?kg WHERE {
  ?inst a futuram:elvDiesel ;
        rdfs:label ?label ;
        futuram:referenceYear ?year ;
        futuram:itemMass [ qudt:numericValue ?kg ; qudt:unit ?u ] .
  FILTER(?year = 2025)
}

