PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX qudt: <http://qudt.org/schema/qudt/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?inst ?label ?year ?mass ?gc_label WHERE {
  ?inst a futuram:elvDiesel ;
        rdfs:label ?label ;
        futuram:referenceYear ?year ;
        futuram:itemMass [ qudt:numericValue ?mass ; qudt:unit ?u ] .
  ?inst futuram:hasCompositionStatement ?stmt .
  ?stmt futuram:hasPartRelation ?pr .
  ?pr   futuram:refersTo ?gc ;
        futuram:hasQuantity/futuram:hasBestValue ?bv .
  ?bv qudt:numericValue ?gc_share ; qudt:unit ?u .
  ?gc rdfs:label ?gc_label .
  FILTER(CONTAINS(STR(?gc_label), "elvGeneralComponents"))
  FILTER(?year=2025)
}

